{"type": "email", "id": "email_001", "subject": "Weekly Sales Team Meeting", "from": "amanda.lee@elexionautomotive.com", "from_name": "Amanda Lee", "to": ["karen.morris@elexionautomotive.com", "daniel.adams@elexionautomotive.com"], "cc": [], "date": "2023-04-01 08:00:00", "body": "Hi team,

